{
  "name": "@lightfastai/ai-sdk",
  "version": "0.2.1",
  "description": "AI agents, tools, and workflows for Lightfast",
  "keywords": [
    "ai",
    "agents",
    "llm",
    "typescript",
    "workflow"
  ],
  "repository": {
    "type": "git",
    "url": "https://github.com/lightfastai/lightfast.git",
    "directory": "core/ai-sdk"
  },
  "homepage": "https://lightfast.ai",
  "bugs": "https://github.com/lightfastai/lightfast/issues",
  "license": "MIT",
  "author": "Lightfast <hello@lightfast.ai>",
  "main": "./dist/index.mjs",
  "types": "./dist/index.d.ts",
  "type": "module",
  "exports": {
    ".": {
      "types": "./dist/index.d.ts",
      "import": "./dist/index.mjs"
    },
    "./client": {
      "types": "./dist/client/index.d.ts",
      "import": "./dist/client/index.mjs"
    },
    "./agent": {
      "types": "./dist/agent.d.ts",
      "import": "./dist/agent.mjs"
    },
    "./tool": {
      "types": "./dist/tool.d.ts",
      "import": "./dist/tool.mjs"
    },
    "./server/adapters/fetch": {
      "types": "./dist/server/adapters/fetch.d.ts",
      "import": "./dist/server/adapters/fetch.mjs"
    },
    "./server/adapters/types": {
      "types": "./dist/server/adapters/types.d.ts",
      "import": "./dist/server/adapters/types.mjs"
    },
    "./memory": {
      "types": "./dist/memory.d.ts",
      "import": "./dist/memory.mjs"
    },
    "./memory/adapters/in-memory": {
      "types": "./dist/memory/adapters/in-memory.d.ts",
      "import": "./dist/memory/adapters/in-memory.mjs"
    },
    "./memory/adapters/redis": {
      "types": "./dist/memory/adapters/redis.d.ts",
      "import": "./dist/memory/adapters/redis.mjs"
    },
    "./cache": {
      "types": "./dist/cache.d.ts",
      "import": "./dist/cache.mjs"
    }
  },
  "scripts": {
    "clean": "rm -rf dist .cache .turbo node_modules",
    "build": "tsup",
    "dev": "tsup --watch",
    "test": "vitest run",
    "test:ui": "vitest --ui",
    "test:coverage": "vitest run --coverage",
    "typecheck": "tsc --noEmit"
  },
  "dependencies": {
    "@upstash/redis": "^1.35.1",
    "@vendor/observability": "workspace:*",
    "ai": "5.0.52",
    "redis": "^4.7.0",
    "resumable-stream": "^2.2.10",
    "uuid": "^11.1.0",
    "zod": "catalog:"
  },
  "devDependencies": {
    "@repo/typescript-config": "workspace:*",
    "@repo/vitest-config": "workspace:*",
    "@types/node": "^24.3.0",
    "@types/uuid": "^10.0.0",
    "@vitest/coverage-v8": "^4.0.18",
    "@vitest/ui": "^4.0.18",
    "tsup": "^8.5.1",
    "typescript": "^5.9.2",
    "vitest": "^4.0.18"
  },
  "engines": {
    "node": ">=18"
  }
}

